mapper.select:

select u.*
from sys_user u


        and (u.user_code like #{keywordLike} or u.user_name like #{keywordLike} or u.account like #{keywordLike})


        and u.department_id = #{departmentId}


        and u.status = #{status}


order by u.status desc, u.updated_at desc

select u.*
from sys_user u
where u.id = #{id}

mapper.update:
update sys_user
set user_code = #{userCode}, user_name = #{userName}, account = #{account}, department_id = #{departmentId},
    auth_mode = #{authMode}, status = #{status}, email = #{email}, mobile = #{mobile}, updated_at = #{updatedAt}
where id = #{id}

update sys_role
set role_code = #{roleCode}, role_name = #{roleName}, description = #{description},
    status = #{status}, sort_no = #{sortNo}, updated_at = #{updatedAt}
where id = #{id}

mapper.select:

select * from sys_data_policy


        and (policy_name like #{keywordLike} or subject_name like #{keywordLike})


        and subject_type = #{subjectType}


        and status = #{status}


order by updated_at desc

mapper.update:
update sys_data_policy
set policy_name = #{policyName}, subject_type = #{subjectType}, subject_id = #{subjectId}, subject_name = #{subjectName},
    data_scope = #{dataScope}, allow_export = #{allowExport}, status = #{status}, updated_at = #{updatedAt}
where id = #{id}
